	.SBTTL	ICOMISC;--------\\; JUMPCAR >;========/; Effectue une routine selon une touche presse.; in	D3.W	touche; out	-; mod	-JUMPCAR:	PUSHM.L	D0,A010$:	TEST.W	(A0)		; fin de la table ?	JUMP',EQ 90$		; oui => 90$20$:	TEST.W	(A0)		; fin liste de touches ?	JUMP',EQ 50$		; oui => 50$	COMP.W	D3,(A0+)	; touche trouve ?	JUMP,NE	20$		; non => 20$30$:				; oui =>	TEST.W	(A0+)		; A0 <-- cherche <ad>	JUMP,NE	 30$	LOAD.W	D0,(A0)		; D0 <-- adresse relative	LOAD.L	A0,#R16"START	ADD.W	A0,D0		; A0 <-- adresse absolue	LOAD.L	(SP)+4*2,A0	; corrige PC de retour !	JUMP'	90$50$:	ADD.L	A0,#4		; A0 <-- saute <0> <ad>	JUMP	10$90$:	POPM.L	D0,A0	RET;--------\; AFMENU  >;========/; Affiche le bon menu selon le contexte.; in	-; out	-; mod	D7.WAFMENU:	PUSHM.L	D7,A3	TEST.B	(A6)+OFLAGS:#BICONE	JUMP',BS 50$	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$	TEST.B	(A6)+OFLAGS:#BTEXT	JUMP',BS 50$				; menu sans "stop" =>	LOAD.L	A3,#R16"TXMEIC	TEST.B	(A6)+OFLAGS:#BCOMM	JUMP',BC 80$	LOAD.L	A3,#R16"TXMECC	JUMP'	80$50$:				; menu avec "stop" =>	LOAD.L	A3,#R16"TXMEIS	TEST.B	(A6)+OFLAGS:#BCOMM	JUMP',BC 80$	LOAD.L	A3,#R16"TXMECS80$:	COMP.L	A3,(A6)+OPMENU	; menu dj affich ?	JUMP',EQ 90$		; oui => 90$	LOAD.L	(A6)+OPMENU,A3	; non =>	LIB	?AFMENU		; affiche le bon menu90$:	POPM.L	D7,A3	RET;---------\; EXCADRE  >;=========/; Envoie une commande de cadrage  l'cran $DIS0.; in	D3.W	touche; out	D7.W	zro => commande effectue correctement; mod	D7.WEXCADRE:	PUSHM.L	D3,D4,D6,A3,A4	LIB	?MINMAJ		; D3 <-- fonction+touche MAJ	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer des commandes	COMP.W	D3,#(2^BSHOW)*H'100+'D	JUMP',NE 10$	LOAD.B	(A4+),#SCRLEFT10$:	COMP.W	D3,#(2^BSHOW)*H'100+'F	JUMP',NE 12$	LOAD.B	(A4+),#SCRRIGHT12$:	COMP.W	D3,#(2^BSHOW)*H'100+'R	JUMP',NE 14$	LOAD.B	(A4+),#SCRUP14$:	COMP.W	D3,#(2^BSHOW)*H'100+'C	JUMP',NE 16$	LOAD.B	(A4+),#SCRDOWN16$:	COMP.W	D3,#(2^BSHOW!2^BPROGRA)*H'100+'D	JUMP',NE 20$	LOAD.B	(A4+),#SCRGHOR20$:	COMP.W	D3,#(2^BSHOW!2^BPROGRA)*H'100+'F	JUMP',NE 22$	LOAD.B	(A4+),#SCRDHOR22$:	COMP.W	D3,#(2^BSHOW!2^BPROGRA)*H'100+'R	JUMP',NE 24$	LOAD.B	(A4+),#SCRMVERT24$:	COMP.W	D3,#(2^BSHOW!2^BPROGRA)*H'100+'C	JUMP',NE 26$	LOAD.B	(A4+),#SCRDVERT26$:	COMP.W	D3,#(2^BSHOW!2^BPROGRA)*H'100+DEFINE	JUMP',NE 30$	LOAD.B	(A4+),#SCRCADRE30$:	CLR.B	(A4)		; termine commande	LOAD.W	D7,#ERILOP	; D7 <-- erreur	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer des commandes	TEST.B	(A4)		; au moins une commande ?	JUMP',EQ 90$		; non => 90$				; oui =>	LOAD.L	A3,#R16"NAMDI0	; A3 <-- ^nom $DIS_0	LOAD.W	D3,#2^BOPWR	; D3 <-- mode d'ouverture	FOS	?OPEN		; ouvre la fentre principale	JUMP',NE 90$	LOAD.W	D3,#TYPDIS	; D3 <-- type "display"	FOS	?COMMAND	PUSH.W	D7	FOS	?CLOSE		; ferme l'cran principal	POP.W	D790$:	POPM.L	D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; INSERT  >;========/; Insre un caractre  la fin de la ligne de commande.; in	D3.B	caractre; out	D7.W	erreur; mod	D7.WINSERT:	PUSHM.L	D4,A3	COMP.B	D3,#'/		; insertion d'un switch ?	JUMP',NE 20$		; non => 20$				; oui =>	CALL	GETLAST		; D3 <-- dernier caractre frapp	COMP.B	D3,#CARMARK	; est-ce une marque ?	JUMP',NE 10$		; non => 10$	CALL	DETRUIT		; oui => dtruit-la10$:	CALL	GETLAST		; D3 <-- dernier caractre frapp	COMP.B	D3,#SPACE	; est-ce un espace ?	JUMP',NE 15$		; non => 15$	CALL	DETRUIT		; oui => dtruit-le15$:	LOAD.B	D3,#'/20$:	LOAD.L	A3,#(A6)+OBUEXE	LOAD.W	D4,#LBUEXE	LOAD.W	D7,#1		; D7 <-- buffer plein30$:	DEC.W	D4	JUMP',EQ 90$	TEST.B	(A3+)		; A3 <-- avance jusqu' la fin	JUMP,NE	30$	LOAD.B	(A3)-1,D3	; ajoute le caractre	CLR.B	(A3)		; remet le terminateur	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; GETLAST >;========/; Donne le dernier caractre frapp.; in	-; out	D3.B	dernier caractre frapp; mod	D3.BGETLAST:	PUSH.L	A3	LOAD.L	A3,#(A6)+OBUEXE10$:	TEST.B	(A3+)		; A3 <-- ^fin du buffer	JUMP,NE	10$	LOAD.B	D3,(A3)-2	; D3 <-- dernier caractre	POP.L	A3	RET;--------\; DETRUIT >;========/; Dtruit le dernier caractre frapp.; in	-; out	D7.W	erreur; mod	D7.WDETRUIT:	PUSHM.L	D3,A3	LOAD.L	A3,#(A6)+OBUEXE	LOAD.W	D7,#1		; D7 <-- buffer vide	TEST.B	(A3)		; buffer dj vide ?	JUMP',EQ 90$		; oui => 90$10$:	TEST.B	(A3+)		; A3 <-- ^fin du buffer	JUMP,NE	10$	CLR.B	(A3)-2		; dtruit le dernier caractre	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D3,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; GETCAR  >;========/; Attend une touche, en ignorant les boutons relachs de la souris.; in	-; out	D3.L	touche;	D7.W	erreur; mod	D3.L, D7.WGETCAR:10$:	LIB	?GETCAR		; attend une touche ...	JUMP',NE 90$	CALL	FILTRE	COMP.W	D3,#KEYMGR	; bouton relach ?	JUMP,EQ	10$		; oui => 10$90$:	TEST.W	D7		; retour EQ/NE	RET;--------\; FILTRE  >;========/; Filtre les touches de la souris presses et relaches.; in	D3.W	touche; out	D3.W	touche (gauche); mod	D3.WFILTRE:	COMP.W	D3,#KEYMGP	; bouton press ?	JUMP',EQ 10$		; oui => 10$	COMP.W	D3,#KEYMMP	JUMP',EQ 10$	COMP.W	D3,#KEYMDP	JUMP',EQ 10$	TCLR.B	(A6)+OFLAGK:#BKEYMP	COMP.W	D3,#KEYMGR	; bouton relach ?	JUMP',EQ 20$		; oui => 20$	COMP.W	D3,#KEYMMR	JUMP',EQ 20$	COMP.W	D3,#KEYMDR	JUMP',EQ 20$	JUMP'	90$10$:	TSET.B	(A6)+OFLAGK:#BKEYMP	LOAD.W	D3,#KEYMGP	; D3 <-- toujours bouton gauche	JUMP'	90$20$:	LOAD.W	D3,#KEYMGR	; D3 <-- toujours bouton gauche90$:	RET;--------\; CLRFIFO >;========/; Vide le fifo du clavier.; in	-; out	-; mod	D7.WCLRFIFO:	PUSHM.L	D3,D6,A4	TCLR.B	(A6)+OFLAGK:#BKEYMP	TEST.B	(A6)+OLEVEL	; utilisateur dbutant ?	JUMP',EQ 90$		; non => 90$				; oui =>	LOAD.L	A4,#(A6)+OBUKEY	LOAD.B	(A4)+0,#KEYCLF	CLR.B	(A4)+1	LOAD.W	D3,#TYPKEY	; D3 <-- type du clavier	LOAD.W	D6,(A6)+OCHKEY	; D6 <-- canal	FOS	?COMMAND	; vide le fifo90$:	POPM.L	D3,D6,A4	RET;--------\; COMPARE >;========/; Compare simplement deux chanes de caractres.; in	A3.L	^chane;	A4.L	^chane; out	D7.W	erreur; mod	D7.WCOMPARE:	PUSHM.L	D3,A3,A4	LOAD.W	D7,#1		; D7 <-- chanes pas gales	COMP.B	(A3),#'"	; chane commence par guillemet ?	JUMP',NE 05$		; non => 05$	INC.L	A3		; oui => saute-le05$:	COMP.B	(A4),#'"	; chane commence par guillemet ?	JUMP',NE 10$		; non => 10$	INC.L	A4		; oui => saute-le10$:	LOAD.B	D3,(A3+)	JUMP',EQ 50$	COMP.B	D3,#CR		; premire chane termine ?	JUMP',EQ 50$		; oui => 50$	COMP.B	D3,#SPACE	JUMP',EQ 50$	COMP.B	D3,#'"	JUMP',EQ 50$	COMP.B	D3,(A4+)	JUMP,EQ	10$	JUMP'	90$50$:	LOAD.B	D3,(A4)	JUMP',EQ 80$	COMP.B	D3,#CR		; deuxime chane aussi termine ?	JUMP',EQ 80$		; oui => 80$	COMP.B	D3,#SPACE	JUMP',EQ 80$	COMP.B	D3,#'"	JUMP',NE 90$80$:	CLR.W	D7		; D7 <-- chanes gales90$:	POPM.L	D3,A3,A4	TEST.W	D7		; retour EQ/NE	RET; Initialisation; --------------;--------\; INIDEF  >;========/; Lit le fichier de dfinitions ICONE.LIST; in	-; out	D7.W	erreur; mod	D7.WINIDEF:	PUSHM.L	D1,D2,D3,D4,D6,A3,A4	CALL	CONFIG		; cherche la configuration	FOS	?OPINFO		; ouvre les infos	LOAD.B	(A6)+OLEVEL,(A4)+OINLEV	CLR.W	D4		; D4 <-- pas de mise  jour	FOS	?CLINFO		; ferme les infos	LOAD.L	A3,#(A6)+ONAMEI	LOAD.W	D3,#2^BOPRD	FOS	?OPEN	JUMP,NE	90$	LOAD.L	D4,#-1	LOAD.B	D3,#-1	FOS	?SPOS		; va tout  la fin	LOAD.L	D2,D4		; D2 <-- lg fichier en bytes	CLR.L	D4	CLR.B	D3	FOS	?SPOS		; revient en dbut	JUMP,NE	90$	LOAD.L	D4,D2		; D4 <-- lg fichier	INC.L	D4		; D4 <-- place pour <0>	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM	JUMP,NE	90$	LOAD.L	(A6)+OPTDEF,A4	DEC.L	D4		; D4 <-- lg sans <0>	CLR.B	(A4)+(D4.L)	; met le <0> tout  la fin	FOS	?RDBYTE		; lit le fichier de df.	JUMP,NE	90$	FOS	?CLOSE	JUMP,NE	90$; Supprime ou conserve les lignes commenant par IF selon; la configuration du systme.	LOAD.L	A3,(A6)+OPTDEF	; A3 <-- ^source	LOAD.L	A4,A3		; A4 <-- ^destination	JUMP	60$		; transfert toujours la 1re ligne40$:	LOAD.B	D3,(A3)		; fin ?	JUMP,EQ	80$		; oui => 80$	LIB	?MINMAJ	COMP.B	D3,#'I		; IF ?	JUMP',NE 60$		; non => 60$				; oui =>	LIB	?SKPNAM		; A3 <-- saute "IF "	LOAD.B	D3,(A3)		; D3 <-- caractre aprs "IF "	LIB	?MINMAJ	LIB	?SKPNAM		; A3 <-- saute CONFIG	COMP.B	D3,(A6)+OCONFIG	; bonne configuration ?	JUMP',EQ 60$		; oui => 60$50$:	LOAD.B	D3,(A3+)	; saute une ligne	JUMP,EQ	80$	COMP.B	D3,#CR	JUMP,NE	50$	COMP.B	(A3),#'-	; <CR>- ?	JUMP,NE	40$		; non => 40$	JUMP	50$60$:	LOAD.B	D3,(A3+)	COMP.B	D3,#SPACE	; supprime espace(s) en dbut de ligne	JUMP,EQ	60$	COMP.B	D3,#TAB	JUMP,EQ	60$	DEC.L	A362$:	LOAD.B	D3,(A3+)	COMP.B	D3,#TAB	JUMP',NE 64$	LOAD.B	D3,#SPACE	; transforme les TAB en SPACE64$:	COMP.B	D3,#'		; cadratin ?	JUMP',NE 65$	LOAD.B	(A4+),#SPACE	JUMP	62$65$:	LOAD.B	(A4+),D3	; transfert une ligne	JUMP,EQ	90$	COMP.B	D3,#SPACE	JUMP,EQ	60$	COMP.B	D3,#CR	JUMP,NE	62$	COMP.B	(A3),#'-	; <CR>- ?	JUMP,NE	40$		; non => 40$	INC.L	A3		; A3 <-- ^aprs le "-"	DEC.L	A4		; ignore les 2 caractres	JUMP	62$80$:	CLR.B	(A4)90$:	POPM.L	D1,D2,D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; KILMARK >;========/; Enlve tous les caractres <CARMARK> dans la ligne de commande.; in	-; out	-; mod	-KILMARK:	PUSHM.L	D3,A3,A4	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^source	LOAD.L	A4,A3		; A4 <-- ^destination10$:	LOAD.B	D3,(A3+)	; fin de la commande ?	JUMP',EQ 50$		; oui => 50$	COMP.B	D3,#CARMARK	; marque ?	JUMP,EQ	10$		; oui => ne la copie pas	LOAD.B	(A4+),D3	; non => copie le caractre	JUMP	10$50$:	CLR.B	(A4)		; termine la commande	POPM.L	D3,A3,A4	RET;--------\; LSTSRC  >;========/; Cherche la chane correspondant  un rang de fichier.; in	D4.W	rang; out	A4.L	^nom du fichier;	D7.W	erreur; mod	D7.W, A4.LLSTSRC:	PUSH.L	D4	LOAD.W	D7,#1		; D7 <-- pas trouv	LOAD.L	A4,(A6)+OSRCPP	; A4 <-- ^buffer des noms10$:	TEST.B	(A4)		; fin du buffer ?	JUMP',EQ 90$		; oui => 90$	TEST.W	D4	JUMP',EQ 80$	LOAD.L	A4,#(A4)+16	; A4 <-- ^suivant	DEC.W	D4	JUMP	10$80$:	CLR.W	D7		; D7 <-- ok90$:	POP.L	D4	TEST.W	D7		; retour EQ/NE	RET;--------\; SYNSRC  >;========/; Cherche la dfinition correspondant  un rang d'icone.; in	D4.W	rang; out	A4.L	^ligne de dfinition;	D7.W	erreur; mod	D7.W, A4.LSYNSRC:	PUSH.L	D4	LOAD.W	D7,#1		; D7 <-- pas trouv	LOAD.L	A4,(A6)+OPTDEF	; A4 <-- ^dfinitions40$:	TEST.B	(A4)		; fin des dfinitions ?	JUMP',EQ 90$		; oui => 90$	COMP.B	(A4+),#CR	JUMP,NE	40$	TEST.B	(A4)		; fin des dfinitions ?	JUMP',EQ 90$		; oui => 90$	TEST.W	D4	JUMP',EQ 80$	DEC.W	D4	JUMP	40$80$:	LOAD.L	(A6)+OPTSEL,A4	; mm. dfinition slectionne	CLR.W	D7		; D7 <-- trouv90$:	POP.L	D4	TEST.W	D7		; retour EQ/NE	RET;--------\; SYNICO  >;========/; Donne le code d'un icone.; in	A4.L	^dbut ligne de dfinition; out	D4.B	numro; mod	D4.LSYNICO:	PUSHM.L	D3,A4	CLR.W	D410$:	LOAD.B	D3,(A4+)	COMP.B	D3,#'0	JUMP',LO 90$	COMP.B	D3,#'9	JUMP',HI 90$	SUB.B	D3,#'0		; D3 <-- 0..9	AND.W	D3,#H'FF	MUL.WU	D4,#10	ADD.W	D4,D3	JUMP	10$90$:	POPM.L	D3,A4	RET;--------\; SKPNAME >;========/; Saute un nom.; in	A3.L	^nom; out	A3.L	^plus loin; mod	A3.LSKPNAME:	PUSHM.L	D2,D3	LOAD.B	D2,#'"	COMP.B	(A3+),#'"	; dbut d'une chane ?	JUMP',EQ 20$		; oui => 20$	LOAD.B	D2,#']	COMP.B	(-A3),#'[	; dbut d'une commande ?	JUMP',EQ 20$		; oui => 20$	LOAD.B	D2,#SPACE20$:	LOAD.B	D3,(A3)	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	INC.L	A3	COMP.B	D3,D2		; terminateur atteint ?	JUMP,NE	20$40$:	COMP.B	(A3+),#SPACE	JUMP,EQ	40$	DEC.L	A390$:	POPM.L	D2,D3	RET;--------\; CONFIG  >;========/; Initialise selon la configuration du systme,  savoir :;	'F	1 floppy;	'D	2 floppy;	'W	winch et floppy; in	-; out	-; mod	D7.WCONFIG:	PUSHM.L	D3,D4,A3,A4	CLR.B	(A6)+OCONFIG	; configuration inconnue	LOAD.L	A3,#R16"TXMM0+1	CLR.W	D3	FOS	?VASSIGN	JUMP',NE 90$	LOAD.B	(A6)+OCONFIG,#'W	COMP.B	(A4)+1,#'W	; nom physique = "$WIN" ?	JUMP',EQ 90$	LOAD.B	(A6)+OCONFIG,#'F	LOAD.L	A3,#R16"TXMM1+1	CLR.W	D3	FOS	?VASSIGN	JUMP',NE 90$	LOAD.B	(A6)+OCONFIG,#'W	COMP.B	(A4)+1,#'W	; nom physique = "$WIN" ?	JUMP',EQ 90$	LOAD.B	(A6)+OCONFIG,#'D90$:	POPM.L	D3,D4,A3,A4	RET	.END